using UnityEngine;

// Novas condições de diálogo (Etapa 5.2) — itens com quantidade, missões,
// inimigos derrotados, itens especiais e NPCs resgatados. Aparecem
// automaticamente no "+ Adicionar Condição" (PolymorphicListDrawer).

/// <summary>Compara a quantidade de um item no inventário (Etapa 4.2) com "quantity".</summary>
[System.Serializable]
public class Condition_HasItemQuantity : NpcCondition
{
    public ItemData item;

    public Comparison comparison = Comparison.GreaterOrEqual;

    [Min(0)] public int quantity = 1;

    public override bool Evaluate(NpcController npc)
    {
        if (PlayerProgress.Instance == null || item == null) return false;

        int actual = PlayerProgress.Instance.GetItemQuantity(item);
        return NpcConditionUtil.Compare(actual, comparison, quantity);
    }
}

/// <summary>Estado de missão verificado por Condition_MissionState.</summary>
public enum MissionStateCheck
{
    /// <summary>A missão já foi iniciada (independentemente de estar concluída).</summary>
    Iniciada,

    /// <summary>A missão ainda não foi iniciada.</summary>
    NaoIniciada,

    /// <summary>A missão já foi concluída.</summary>
    Concluida,

    /// <summary>A missão ainda não foi concluída.</summary>
    NaoConcluida,

    /// <summary>A missão está em curso (iniciada e ainda não concluída).</summary>
    EmCurso
}

/// <summary>Verifica o estado de uma missão (Etapa 5.1 — MissionManager/GameVariables).</summary>
[System.Serializable]
public class Condition_MissionState : NpcCondition
{
    public MissionData mission;

    public MissionStateCheck state = MissionStateCheck.EmCurso;

    public override bool Evaluate(NpcController npc)
    {
        var mm = MissionManager.Instance;
        if (mm == null || mission == null) return false;

        switch (state)
        {
            case MissionStateCheck.Iniciada: return mm.IsMissionStarted(mission);
            case MissionStateCheck.NaoIniciada: return !mm.IsMissionStarted(mission);
            case MissionStateCheck.Concluida: return mm.IsMissionCompleted(mission);
            case MissionStateCheck.NaoConcluida: return !mm.IsMissionCompleted(mission);
            case MissionStateCheck.EmCurso: return mm.IsMissionStarted(mission) && !mm.IsMissionCompleted(mission);
            default: return false;
        }
    }
}

/// <summary>Estado de uma tarefa de missão verificado por Condition_MissionTaskState.</summary>
public enum MissionTaskStateCheck
{
    /// <summary>A tarefa já está concluída.</summary>
    Concluida,

    /// <summary>A tarefa ainda não está concluída.</summary>
    NaoConcluida,

    /// <summary>A tarefa está ACTIVA: a missão está em curso, a tarefa ainda não está concluída e todas as suas "Depends On Task Ids" já estão concluídas.</summary>
    Activa,

    /// <summary>A tarefa NÃO está activa (já concluída, missão não iniciada/concluída, ou ainda bloqueada por dependências).</summary>
    NaoActiva
}

/// <summary>
/// Verifica o estado de uma tarefa específica de uma missão (Sistema de
/// Missões — Missão > Tarefa, tarefas não-lineares). Identifica a tarefa pelo
/// seu "Task Id" (ver MissionTask.taskId) — usar, por exemplo, num
/// "Action_ConditionalBranch" para um NPC reagir de forma diferente dependendo
/// de quais tarefas o jogador já concluiu (independentemente da ordem).
/// </summary>
[System.Serializable]
public class Condition_MissionTaskState : NpcCondition
{
    public MissionData mission;

    [Tooltip("\"Task Id\" da tarefa a verificar (ver MissionTask.taskId — se vazio nessa tarefa, o id efectivo é \"tarefa_<índice>\", 0 = primeira).")]
    public string taskId;

    public MissionTaskStateCheck state = MissionTaskStateCheck.Concluida;

    public override bool Evaluate(NpcController npc)
    {
        var mm = MissionManager.Instance;
        if (mm == null || mission == null) return false;

        var task = mission.FindTask(taskId);
        if (task == null) return false;

        switch (state)
        {
            case MissionTaskStateCheck.Concluida: return mm.IsTaskCompleted(mission, task);
            case MissionTaskStateCheck.NaoConcluida: return !mm.IsTaskCompleted(mission, task);
            case MissionTaskStateCheck.Activa: return mm.IsTaskActive(mission, task);
            case MissionTaskStateCheck.NaoActiva: return !mm.IsTaskActive(mission, task);
            default: return false;
        }
    }
}

/// <summary>
/// Um inimigo específico da cena (por "Enemy Instance Id" — EnemyController
/// registry) foi derrotado (Morto e, opcionalmente, Desactivado).
/// </summary>
[System.Serializable]
public class Condition_EnemyDefeated : NpcCondition
{
    [Tooltip("Enemy Instance Id do inimigo (campo 'Identidade' do EnemyController na cena).")]
    public string enemyInstanceId;

    [Tooltip("Desactivado também conta como derrotado (GDD 12.1: neutralizar = destruir OU desligar).")]
    public bool deactivatedCounts = true;

    [Tooltip("Se o inimigo não existir na cena (já foi destruído/é de outra área), conta como derrotado.")]
    public bool missingCountsAsDefeated = false;

    public override bool Evaluate(NpcController npc)
    {
        var enemy = EnemyController.FindById(enemyInstanceId);
        if (enemy == null) return missingCountsAsDefeated;

        return enemy.IsDead || (deactivatedCounts && enemy.IsDeactivated);
    }
}

/// <summary>O player já recolheu este item especial (registo persistente de drops únicos — Etapa 4.3).</summary>
[System.Serializable]
public class Condition_SpecialItemCollected : NpcCondition
{
    public ItemData item;

    public override bool Evaluate(NpcController npc)
    {
        return PlayerProgress.Instance != null && PlayerProgress.Instance.HasCollectedSpecialItem(item);
    }
}

/// <summary>
/// Um NPC foi resgatado. Reutiliza o padrão de variável global (GameVariables):
/// o evento de resgate deve ligar a variável com Action_SetBoolVariable.
/// </summary>
[System.Serializable]
public class Condition_NpcRescued : NpcCondition
{
    [Tooltip("Identificador do NPC resgatado. A condição lê a variável global \"NpcResgatado_<npcId>\" (ou 'variableName', se preenchido).")]
    public string npcId;

    [Tooltip("Nome explícito da variável global bool a ler (vazio = \"NpcResgatado_<npcId>\").")]
    public string variableName = "";

    public bool expectedValue = true;

    public override bool Evaluate(NpcController npc)
    {
        var vars = GameVariables.Instance;
        if (vars == null) return false;

        string name = !string.IsNullOrEmpty(variableName) ? variableName : $"NpcResgatado_{npcId}";
        return vars.GetBool(name) == expectedValue;
    }
}
